changeSet.sql:
-- remember the old OID values
create temp table old_oids
as
select distinct content::oid as lo_ptr
from content;

-- add temporary column to store large object data
ALTER TABLE content add column content_bytea bytea;

-- convert the large object to bytea
UPDATE content
SET content_bytea = loread(lo_open(content::oid, 262144), 100000000);

-- copy large object data from temporary column to regular content column
ALTER TABLE content drop column content;
ALTER TABLE content rename column content_bytea to content;

-- remove the old large objects as they are not removed automatically
select lo_unlink(lo_ptr)
from old_oids;

drop table old_oids;
